input.command:
kubectl patch statefulset es-cluster -n elasticsearch --type=json -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "es-log4j2-config",
      "configMap": {
        "name": "es-log4j2-config",
        "items": [{"key": "log4j2.properties", "path": "log4j2.properties"}]
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "es-log4j2-config",
      "mountPath": "/usr/share/elasticsearch/config/log4j2.properties",
      "subPath": "log4j2.properties",
      "readOnly": true
    }
  }
]' 2>/dev/null && echo "StatefulSet patched"
